    { id: 'claude3', name: 'Sonnet 3.5', provider: 'Anthropic', color: 'text-amber-400', icon: Zap },
    { id: 'gemini15', name: 'Flash 1.5', provider: 'Google', color: 'text-blue-400', icon: Cpu },
];

export default function Comparison() {
