                                    </div>
                                </div>
                                <div className={`w-2 h-2 rounded-full ${loading ? 'bg-amber-500 animate-ping' : 'bg-emerald-500'}`} />
                            </div>

                            <div className="flex-1 p-8 overflow-y-auto custom-scrollbar relative z-10">
                                {loading ? (
