                                        <div className="h-4 shimmer w-full rounded-full" />
                                        <div className="h-4 shimmer w-[90%] rounded-full" />
                                        <div className="h-4 shimmer w-[95%] rounded-full" />
                                        <div className="h-4 shimmer w-[40%] rounded-full" />
                                    </div>
                                ) : responses[model.id] ? (
