                                        </div>
                                    </button>
                                </div>
                            </div>

                            <button onClick={() => setShowPrefs(false)} className="w-full mt-10 py-5 bg-white text-black rounded-3xl font-black uppercase tracking-widest text-[11px] hover:scale-105 transition-all">Save Protocols</button>
                        </motion.div>
