                )}
            </AnimatePresence>
            {/* Login Modal for Guest limit */}
            <LoginModal isOpen={showLoginModal} onClose={() => setShowLoginModal(false)} />

            {/* Guest Initial Popup */}
            <AnimatePresence>
                {showGuestPopup && (
